# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
    guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
          let url = userActivity.webpageURL,
          let components = NSURLComponents(url: url, resolvingAgainstBaseURL: true) else {
        return false
    }

    if let path = components.path,
       let params = components.queryItems,
       path == "/reset-password" {
        handlePasswordReset(params: params)
    }

    return true
}

func handlePasswordReset(params: [URLQueryItem]) {
    let token = params.first(where: { $0.name == "token" })?.value ?? ""
    // Navigate to password reset screen with the token
    let passwordResetVC = PasswordResetViewController(token: token)
    window?.rootViewController?.present(passwordResetVC, animated: true, completion: nil)
}